import{c as e,Q as a,j as n,m as r}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Tenants","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/tenants.md","filePath":"guide/admin/tenants.md","lastUpdated":1779094756000}'),o={name:"guide/admin/tenants.md"};function i(s,t,l,d,g,c){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="tenants" tabindex="-1">Tenants <a class="header-anchor" href="#tenants" aria-label="Permalink to &quot;Tenants&quot;">​</a></h1><p>The <strong>Tenants</strong> page lists every provisioned tenant across every customer and instance. From here you create new tenants, change their lifecycle, and drill into a tenant for detailed configuration, users, insights, and activity.</p><p>See <a href="./../concepts/customers-tenants-instances">Customers, Tenants &amp; Instances</a> for the conceptual model.</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><ul><li><strong>Search</strong> — matches tenant name or customer name.</li><li><strong>Status</strong> — All / Active / Suspended / Deleted / Provisioning.</li><li><strong>Customer</strong> — filter by customer.</li><li><strong>Instance</strong> — filter by instance.</li><li><strong>Clear</strong> — appears when any filter is active.</li><li><strong>New Tenant</strong> button (top right).</li><li>Count chip — &quot;N tenants&quot; or &quot;N of X&quot; when filtered.</li></ul><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Tenant Name</strong></td><td>Clickable link to the tenant detail page.</td></tr><tr><td><strong>Customer</strong></td><td>Owning customer.</td></tr><tr><td><strong>Instance</strong></td><td>Hosting instance.</td></tr><tr><td><strong>Status</strong></td><td>Active / Suspended / Deleted / Provisioning. A red sync-failure badge appears beside the status if sync is failing or stuck (with the attempt count).</td></tr><tr><td><strong>Created</strong></td><td>Relative timestamp.</td></tr><tr><td><strong>Actions</strong></td><td>Row-hover icon buttons.</td></tr></tbody></table><h3 id="row-actions" tabindex="-1">Row actions <a class="header-anchor" href="#row-actions" aria-label="Permalink to &quot;Row actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Available when</th><th>Required role</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Suspend</strong> (pause icon)</td><td>Active</td><td>Any internal role with the tenant in scope</td><td>Direct action — no modal.</td></tr><tr><td><strong>Resume</strong> (play icon)</td><td>Suspended</td><td>Any internal role with the tenant in scope</td><td>Direct action.</td></tr><tr><td><strong>Delete</strong> (trash icon)</td><td>Active or Suspended</td><td><code>platform_admin</code> or <code>infra_ops</code> only</td><td>Modal with a <strong>required reason</strong>. Purges Mongo data and marks the tenant <code>deleted</code>. Terminal — no restore.</td></tr></tbody></table><p>Account managers and QA admins see Suspend / Resume on tenants within their assigned scope, but Delete is hidden from them. See <a href="./../../internal/roles-and-permissions#21-tenant-lifecycle-actions">roles-and-permissions.md §2.1</a> for the full matrix.</p><h2 id="creating-a-new-tenant" tabindex="-1">Creating a new tenant <a class="header-anchor" href="#creating-a-new-tenant" aria-label="Permalink to &quot;Creating a new tenant&quot;">​</a></h2><p>Click <strong>New Tenant</strong>. The modal has multiple sections:</p><h3 id="basics-required" tabindex="-1">Basics (required) <a class="header-anchor" href="#basics-required" aria-label="Permalink to &quot;Basics (required)&quot;">​</a></h3><ul><li><strong>Name</strong> — display name.</li><li><strong>Customer</strong> — owning customer.</li><li><strong>Instance</strong> — target instance.</li><li><strong>Environment</strong> — DEV / QA / UAT / STAGING / DEMO / PRE_PROD / PROD.</li><li><strong>Description</strong>.</li></ul><h3 id="licensing-modules-required" tabindex="-1">Licensing &amp; Modules (required) <a class="header-anchor" href="#licensing-modules-required" aria-label="Permalink to &quot;Licensing &amp; Modules (required)&quot;">​</a></h3><ul><li><strong>User License Count</strong> — total user seats.</li><li><strong>Project License Count</strong> — total project seats.</li><li><strong>License Expiration Date</strong> — required.</li><li><strong>Modules</strong> — multi-select chip group. The <code>CONFIG_MODULES</code> module is added automatically.</li></ul><h3 id="primary-contact-optional" tabindex="-1">Primary Contact (optional) <a class="header-anchor" href="#primary-contact-optional" aria-label="Permalink to &quot;Primary Contact (optional)&quot;">​</a></h3><ul><li><strong>Name</strong>, <strong>Phone</strong>, <strong>Email</strong>.</li></ul><h3 id="address-optional" tabindex="-1">Address (optional) <a class="header-anchor" href="#address-optional" aria-label="Permalink to &quot;Address (optional)&quot;">​</a></h3><ul><li><strong>Street</strong>, <strong>City</strong>, <strong>Pincode</strong>, <strong>Country</strong>.</li></ul><h3 id="features-optional" tabindex="-1">Features (optional) <a class="header-anchor" href="#features-optional" aria-label="Permalink to &quot;Features (optional)&quot;">​</a></h3><ul><li><strong>GeoTagging</strong>, <strong>Angular Dashboard</strong>, <strong>PowerBI Dashboard</strong> toggles.</li></ul><h3 id="tags-optional" tabindex="-1">Tags (optional) <a class="header-anchor" href="#tags-optional" aria-label="Permalink to &quot;Tags (optional)&quot;">​</a></h3><p>Key-value editor for free-form metadata.</p><p>Click <strong>Create Tenant</strong>. The tenant enters <code>provisioning</code> status while the target instance is prepared, then transitions to <code>active</code>.</p><h2 id="tenant-detail-page" tabindex="-1">Tenant detail page <a class="header-anchor" href="#tenant-detail-page" aria-label="Permalink to &quot;Tenant detail page&quot;">​</a></h2><h3 id="header" tabindex="-1">Header <a class="header-anchor" href="#header" aria-label="Permalink to &quot;Header&quot;">​</a></h3><ul><li>Tenant name and status badge.</li><li>Action buttons appropriate to the status — <strong>Suspend</strong> / <strong>Resume</strong> / <strong>Delete</strong> / <strong>Move</strong>. Same role gates as the list-page row actions; <strong>Move</strong> additionally requires <code>platform_admin</code>.</li></ul><h3 id="banners" tabindex="-1">Banners <a class="header-anchor" href="#banners" aria-label="Permalink to &quot;Banners&quot;">​</a></h3><ul><li><strong>Pending Grants</strong> — appears when user grants are stuck. Click <strong>Reissue grants</strong> to retry.</li><li><strong>Sync Status</strong> — red if sync is failing, with the attempt count and last error. Click <strong>Retry sync</strong>. Neutral if pending. Hidden if in sync.</li></ul><h3 id="overview-tab" tabindex="-1">Overview tab <a class="header-anchor" href="#overview-tab" aria-label="Permalink to &quot;Overview tab&quot;">​</a></h3><p>Cards in a two-column grid. Each is editable independently with <strong>Edit</strong> / <strong>Save</strong> / <strong>Cancel</strong> buttons.</p><ul><li><strong>Details</strong> — Name, Environment, Description, Idle Timeout (0 = disabled), Created, Updated, Customer link, Instance link, Tenant ID (immutable).</li><li><strong>Licensing &amp; Features</strong> — User/Project license counts, License Expiration, GeoTagging / Angular / PowerBI toggles.</li><li><strong>Address</strong> — Street, City, Country, Pincode.</li><li><strong>Primary Contact</strong> — Name, Phone, Email.</li><li><strong>Modules</strong> — chip list; edit mode shows a multi-select.</li></ul><h3 id="users-tab" tabindex="-1">Users tab <a class="header-anchor" href="#users-tab" aria-label="Permalink to &quot;Users tab&quot;">​</a></h3><p>A server-paginated table of users assigned to this tenant.</p><p><strong>Columns:</strong> Name, Email, Role (Tenant User / Tenant Admin selector), Status, Provisioned instances, Actions.</p><p><strong>Filters:</strong> Status, Role.</p><p><strong>Toolbar buttons:</strong></p><ul><li><strong>Invite Users</strong> — bulk invite directly into this tenant.</li><li><strong>Bulk Assign</strong> — assign existing customer users to this tenant in one action.</li></ul><p>Per-row actions include changing role inline, suspending or reactivating, and resending invites.</p><h3 id="insights-tab" tabindex="-1">Insights tab <a class="header-anchor" href="#insights-tab" aria-label="Permalink to &quot;Insights tab&quot;">​</a></h3><p>Usage analytics for the tenant.</p><ul><li>Date range toggle — 7d / 30d / 90d.</li><li>Summary cards — MAU, Avg DAU, Workflow executions, Avg Error Rate.</li><li>Tables side by side — Daily Active Users (date + sparkline), Workflow Executions, Error Rate.</li></ul><h3 id="activity-tab" tabindex="-1">Activity tab <a class="header-anchor" href="#activity-tab" aria-label="Permalink to &quot;Activity tab&quot;">​</a></h3><p>A chronological timeline of changes to this tenant — who edited what, when, with metadata. Driven by the audit log.</p><h2 id="moving-a-tenant" tabindex="-1">Moving a tenant <a class="header-anchor" href="#moving-a-tenant" aria-label="Permalink to &quot;Moving a tenant&quot;">​</a></h2><p>Click <strong>Move</strong> in the header. A modal asks for the <strong>target customer</strong>. On confirmation the Console shows a detailed summary: assignments relinked, users created, grants issued, deduplicated, failed, billing updated.</p><p>Moving a tenant changes ownership only. The tenant stays on the same instance with the same environment, modules, and licensing.</p><h2 id="migrating-a-tenant-to-a-different-instance" tabindex="-1">Migrating a tenant to a different instance <a class="header-anchor" href="#migrating-a-tenant-to-a-different-instance" aria-label="Permalink to &quot;Migrating a tenant to a different instance&quot;">​</a></h2><p>Tenant migration happens through the <a href="./migrations">Migrations</a> page — not from the tenant detail page. Use a Tenant Clone or Tenant Export/Import job there.</p>',51)])])}const p=e(o,[["render",i]]);export{u as __pageData,p as default};
